 1	import * as React from 'react';
 2	import { ActionGroup, Button } from '@patternfly/react-core';
 3	import { useTranslation } from 'react-i18next';
 4	import { YellowExclamationTriangleIcon } from '@openshift-console/dynamic-plugin-sdk';
 5	import {
 6	  createModalLauncher,
 7	  ModalBody,
 8	  ModalComponentProps,
 9	  ModalFooter,
10	  ModalTitle,
11	} from './modal';
12	import { HandlePromiseProps, withHandlePromise } from './promise-component';
13	
14	export const ModalErrorContent = withHandlePromise<ErrorModalProps>((props) => {
15	  const { t } = useTranslation('plugin__pipelines-console-plugin');
16	  const { error, title, cancel } = props;
17	  const titleText = title || t('Error');
18	  return (
19	    <div className="modal-content">
20	      <ModalTitle>
21	        <YellowExclamationTriangleIcon className="co-icon-space-r" />{' '}
22	        {titleText}
23	      </ModalTitle>
24	      <ModalBody>{error}</ModalBody>
25	      <ModalFooter inProgress={false} errorMessage="">
26	        <ActionGroup className="pf-v6-c-form pf-v6-c-form__actions--right pf-v6-c-form__group--no-top-margin">
27	          <Button type="button" variant="primary" onClick={cancel}>
28	            {t('OK')}
29	          </Button>
30	        </ActionGroup>
31	      </ModalFooter>
32	    </div>
33	  );
34	});
35	
36	export const errorModal = createModalLauncher(ModalErrorContent);
37	
38	export type ErrorModalProps = {
39	  error: string;
40	  title?: string;
41	} & ModalComponentProps &
42	  HandlePromiseProps;

